// Deterministic prompt builder. It uses the selling-point LLM output when available,
// but does not make a second LLM call, so the image pipeline is not blocked by model routing.
const product = $("读取商品与风格").item.json;
const taskParams = product.task_parameters || {};
const strategy = taskParams.prompt_strategy || {};
const requestedCount = Math.max(1, Number(product.requested_count || taskParams.requested_count || 11));

function parseJsonLoose(value) {
  if (value && typeof value !== 'string') return value;
  let text = String(value || '').trim();
  text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  const firstObject = text.indexOf('{');
  const lastObject = text.lastIndexOf('}');
  if (firstObject >= 0 && lastObject > firstObject) text = text.slice(firstObject, lastObject + 1);
  try { return JSON.parse(text); } catch (_) { return { selling_points: [] }; }
}

function asList(value) {
  if (Array.isArray(value)) return value.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
  if (!value) return [];
  return String(value).split(/[;?,?\n]+/).map(v => v.trim()).filter(Boolean);
}

function uniqueList(values) {
  const out = [];
  const seen = new Set();
  (values || []).flat().forEach(v => {
    if (!v) return;
    const s = String(v).trim();
    if (!s) return;
    const key = s.toLowerCase();
    if (!seen.has(key)) { seen.add(key); out.push(s); }
  });
  return out;
}

const sellingAnalysis = parseJsonLoose($input.first().json.choices?.[0]?.message?.content || '');
const rawSellingPoints = asList(product.raw_selling_points);
const analysedPoints = asList((sellingAnalysis.selling_points || []).map(p => p.visual_translation || p.claim || p.text_en || p.text_cn));
const sellingPoints = uniqueList([analysedPoints, rawSellingPoints]).slice(0, 6);
const scenes = asList(product.use_scenarios).length ? asList(product.use_scenarios) : ['clean studio', 'lifestyle training space', 'outdoor active scene'];
const blockedBrands = uniqueList([
  'Nike', 'Nike Swoosh', 'swoosh logo', 'Li-Ning', '??', 'lining logo', 'adidas', 'three stripes',
  'Puma', 'Under Armour', 'Lululemon', 'Anta', '??', 'Jordan', 'New Balance', 'Reebok', 'ASICS', 'Fila', 'Decathlon',
  strategy.blocked_brand_terms || [], (sellingAnalysis.forbidden_brands || [])
]);
const authorizedBrand = String(strategy.authorized_brand_text || '').trim();
const logoPolicy = strategy.logo_policy || 'no_logo';
const logoRule = authorizedBrand && logoPolicy !== 'no_logo'
  ? `only authorized brand/logo may appear: ${authorizedBrand}; no other brand marks or readable labels`
  : 'plain unbranded apparel, no visible logo, no text label, no slogan, no badge, no hangtag text';
const negative = uniqueList([
  strategy.negative_prompt || '', product.style_negative_prompt || '',
  'third-party brand logo', 'unauthorized trademark', 'unauthorized wordmark', 'random letters', 'random numbers',
  'slogan text', 'hangtag text', 'watermark', 'text overlay', 'distorted garment construction', 'bad anatomy',
  blockedBrands
]).join(', ');

const category = product.category || 'apparel';
const color = product.primary_color || 'neutral product color';
const name = product.name_cn || product.name_en || 'product';
const sku = product.sku || 'SKU';
const guardrails = asList(strategy.visual_guardrails);
const identityParts = uniqueList([
  strategy.consistency?.garment_identity_hint || '',
  `${sku} ${name}`, category, `primary color ${color}`, sellingPoints.join('; '), logoRule,
  guardrails.join('; ')
]);
const sharedIdentity = identityParts.join('; ').slice(0, 1100);

const defaultShots = [
  ['studio_front', 'product_front', 'clean studio front view, full upper body, eye-level framing, soft commercial lighting', '1024x1024'],
  ['studio_side', 'product_side', 'clean studio side profile, show fit and side seams, controlled shadow, sharp product detail', '1024x1024'],
  ['studio_back', 'product_back', 'clean studio back view, show back construction and support zones, neutral background', '1024x1024'],
  ['fabric_macro', 'detail_fabric', 'macro close-up of fabric surface and breathable texture, no face, no logo, product-detail lighting', '1024x1024'],
  ['closure_detail', 'detail_closure', 'close-up action detail of closure or key construction feature, hands natural, product remains accurate', '1024x1024'],
  ['support_detail', 'detail_support', 'three-quarter crop highlighting structure, support, stitching and material finish, no readable text', '1024x1024'],
  ['scene_primary', 'lifestyle_scene', `${scenes[0]} lifestyle image, natural pose, full product readable, vertical social composition`, '1536x2048'],
  ['scene_secondary', 'lifestyle_scene', `${scenes[1] || scenes[0]} active-use image, controlled motion, garment identity unchanged`, '1536x2048'],
  ['scene_tertiary', 'lifestyle_scene', `${scenes[2] || scenes[0]} commercial lifestyle image, product clarity prioritized`, '1536x2048'],
  ['scene_close', 'lifestyle_detail', 'lifestyle close crop showing material and fit in use, consistent model and garment identity', '1536x2048'],
  ['hero_social', 'hero_commerce', 'premium ecommerce hero image, centered confident pose, clean background depth, strong product readability', '1536x2048']
];
const userPlan = asList(strategy.shot_plan).map((line, idx) => [
  `user_shot_${String(idx + 1).padStart(2, '0')}`, 'user_planned', line, idx >= 6 ? '1536x2048' : '1024x1024'
]);
const shots = (userPlan.length ? userPlan : defaultShots);
let batchSeed = 0;
for (const ch of String(product.task_id || sku || 'content-factory')) {
  batchSeed = ((batchSeed * 31) + ch.charCodeAt(0)) >>> 0;
}
batchSeed = Math.max(100000, batchSeed % 1900000000);
const prompts = [];
for (let idx = 0; idx < requestedCount; idx += 1) {
  const shot = shots[idx % shots.length];
  const point = sellingPoints[idx % Math.max(1, sellingPoints.length)] || 'product clarity and commercial usefulness';
  const enPrompt = [
    `Commerce-grade image for ${name}, ${category}, ${color}.`,
    `Garment identity lock: ${sharedIdentity}.`,
    `Shot direction: ${shot[2]}.`,
    `Visual selling point: ${point}.`,
    'Preserve exact same garment category, silhouette, color undertone, fabric finish, seams, panels, closure, neckline and logo policy across the full batch.',
    `Brand safety: ${logoRule}.`,
    'Professional ecommerce photography, realistic anatomy, clean lighting, product remains readable and commercially usable.'
  ].join(' ');
  prompts.push({
    shot_id: shot[0],
    shot_type: shot[1],
    en_prompt: enPrompt,
    suggested_size: shot[3],
    ref_image_ids: [],
    guidance_scale: strategy.creative_latitude === 'strict' ? 4.5 : 5.5,
    seed_hint: batchSeed + idx * 9973,
    fact_refs: ['product.name', 'product.category', 'product.primary_color', 'product.selling_points'],
    must_show: [name, category, color, point, logoRule],
    must_not_change: ['garment identity', 'primary color', 'silhouette and fit', 'fabric finish', 'logo policy'],
    forbidden_inventions: ['third-party logo', 'readable garment text', 'unauthorized label or hangtag', ...blockedBrands.map(b => `${b} logo or wordmark`)],
    negative_prompt: negative,
    quality_check: { product_truth: true, no_third_party_logo: true, same_garment_identity: true }
  });
}

const payload = {
  shared_garment_identity: sharedIdentity,
  shared_negative_prompt: negative,
  forbidden_brands: blockedBrands,
  locked_facts: uniqueList([sku, name, category, color, sellingPoints]),
  prompts
};
return [{ json: { choices: [{ message: { content: JSON.stringify(payload) } }] } }];

// Parse the LLM JSON content and explode into one item per image prompt.
const raw = $input.first().json.choices?.[0]?.message?.content;
function parseJsonLoose(value) {
  if (value && typeof value !== 'string') return value;
  let text = String(value || '').trim();
  text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  const firstObject = text.indexOf('{');
  const lastObject = text.lastIndexOf('}');
  if (firstObject >= 0 && lastObject > firstObject) {
    text = text.slice(firstObject, lastObject + 1);
  }
  return JSON.parse(text);
}
let parsed;
try {
  parsed = parseJsonLoose(raw);
} catch (e) {
  throw new Error('LLM did not return parseable JSON: ' + e.message + ' raw=' + String(raw || '').slice(0, 180));
}
const product = $("读取商品与风格").item.json;
const taskParams = product.task_parameters || {};
const strategy = taskParams.prompt_strategy || {};
const requestedCount = Math.max(1, Number(product.requested_count || taskParams.requested_count || 11));
if (!parsed.prompts || !Array.isArray(parsed.prompts) || parsed.prompts.length < requestedCount) {
  throw new Error('Expected ' + requestedCount + ' prompts in LLM response, got ' + (parsed.prompts ? parsed.prompts.length : 0));
}
const defaultForbiddenBrands = [
  'Nike', 'NIKE', 'Nike Swoosh', 'swoosh logo', 'Li-Ning', 'LI-NING', '\u674e\u5b81', 'lining logo',
  'adidas', 'ADIDAS', 'three stripes', 'trefoil logo', 'Puma', 'Under Armour', 'Lululemon',
  'Anta', '\u5b89\u8e0f', 'Jordan', 'Jumpman', 'New Balance', 'Reebok', 'ASICS', 'Fila', 'Decathlon'
];
const blockedBrandTerms = Array.from(new Set([
  ...defaultForbiddenBrands,
  ...((strategy.blocked_brand_terms || strategy.forbidden_brands || [])),
  ...((parsed.forbidden_brands || []))
].filter(Boolean).map(v => String(v).trim()).filter(Boolean)));
const brandNegative = [
  'third-party brand logo', 'third-party brand name', 'unauthorized trademark', 'unauthorized wordmark',
  'unauthorized monogram', 'unauthorized chest logo', 'unauthorized sleeve logo', 'unauthorized waistband logo',
  'random letters', 'random numbers', 'slogan text', 'hangtag text', 'branded background signage',
  'lookalike sportswear branding', 'fake logo', 'extra logo', 'duplicated logo', 'logo moved from reference',
  ...blockedBrandTerms
].join(', ');
const authorizedBrand = String(strategy.authorized_brand_text || '').trim();
const logoPolicy = strategy.logo_policy || 'no_logo';
const logoRule = authorizedBrand && logoPolicy !== 'no_logo'
  ? `only authorized brand/logo may appear: ${authorizedBrand}; no other brand marks or readable labels`
  : 'plain unbranded garment, no visible logo, no text label, no slogan, no badge, no hangtag text';
const sellingPoints = Array.isArray(product.raw_selling_points)
  ? product.raw_selling_points.join('; ')
  : String(product.raw_selling_points || '');
const attributes = product.attributes_json || {};
const attributeBits = [
  attributes.sub_category || attributes.product_type || '',
  attributes.silhouette || attributes.fit || '',
  attributes.material_main || attributes.material || '',
  attributes.fabric_finish || '',
  attributes.closure_type || attributes.closure || '',
  attributes.neckline || '',
  attributes.logo_placement || ''
].filter(Boolean).join(', ');
const consistency = strategy.consistency || {};
const fallbackGarmentIdentity = [
  consistency.garment_identity_hint || '',
  product.name_cn || product.name_en || '',
  product.category || '',
  product.primary_color ? `primary color ${product.primary_color}` : '',
  sellingPoints ? `selling points ${sellingPoints}` : '',
  attributeBits ? `attributes ${attributeBits}` : '',
  product.canonical_model_ref ? `reference ${product.canonical_model_ref}` : ''
].filter(Boolean).join('; ');
const garmentIdentity = uniqueList([parsed.shared_garment_identity || '', fallbackGarmentIdentity]).join('; ').slice(0, 1100);
let batchSeed = 0;
for (const ch of String(product.task_id || product.sku || 'content-factory')) {
  batchSeed = ((batchSeed * 31) + ch.charCodeAt(0)) >>> 0;
}
batchSeed = Math.max(100000, batchSeed % 1900000000);
const sharedNeg = [brandNegative, parsed.shared_negative_prompt, strategy.negative_prompt, product.style_negative_prompt]
  .filter(Boolean).join(', ');
function uniqueList(values) {
  const out = [];
  const seen = new Set();
  (values || []).flat().forEach(v => {
    if (!v) return;
    const s = String(v).trim();
    if (!s) return;
    const key = s.toLowerCase();
    if (!seen.has(key)) { seen.add(key); out.push(s); }
  });
  return out;
}
const runId = $("写入生成批次").item.json.id;
const sku = product.sku;
const productId = product.product_id;
const taskId = product.task_id;
const productRefs = product.reference_image_ids || [];
const refLookup = {};
productRefs.forEach((ref, idx) => {
  if (typeof ref === 'string' && /^https?:\/\//i.test(ref)) {
    refLookup[`product_ref_${idx + 1}`] = ref;
    refLookup[`ref_${idx + 1}`] = ref;
  }
});
function refToUrl(refId) {
  if (!refId || typeof refId !== 'string') return null;
  if (/^https?:\/\//i.test(refId)) return refId;
  if (refLookup[refId]) return refLookup[refId];
  if (refId.startsWith('scene_ref_')) {
    return `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/refs/scenes/${refId}.jpg`;
  }
  return `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/refs/${sku}/${refId}.jpg`;
}

return parsed.prompts.slice(0, requestedCount).map((p, idx) => ({
  json: {
    run_id: runId,
    task_id: taskId,
    product_id: productId,
    sku: sku,
    shot_id: p.shot_id || `shot_${String(idx + 1).padStart(2, '0')}`,
    shot_type: p.shot_type || 'auto',
    en_prompt: [
      garmentIdentity ? `GARMENT IDENTITY LOCK: ${garmentIdentity}. Keep this exact same garment across the whole image batch; only pose, camera, crop, lighting, and background may change.` : '',
      p.en_prompt || '',
      `Batch consistency: same clothing category, cut, fit, color, fabric finish, seams, panels, closure, neckline, and logo/label policy as every other image in this task.`,
      `Brand safety: ${logoRule}.`
    ].filter(Boolean).join(' '),
    negative_prompt: [p.negative_prompt, sharedNeg].filter(Boolean).join(', '),
    suggested_size: p.suggested_size || (String(p.shot_type || '').includes('scene') ? '1536x2048' : '2048x2048'),
    ref_image_ids: p.ref_image_ids || [],
    guidance_scale: p.guidance_scale || (strategy.creative_latitude === 'strict' ? 4.5 : 5.5),
    seed: p.seed_hint || (batchSeed + idx * 9973),
    fact_refs: p.fact_refs || [],
    garment_identity: garmentIdentity,
    authorized_brand_text: authorizedBrand,
    logo_policy: logoPolicy,
    forbidden_brand_terms: blockedBrandTerms,
    must_show: uniqueList([p.must_show || [], logoRule]),
    must_not_change: uniqueList([p.must_not_change || [], `brand/logo rule: ${logoRule}`, garmentIdentity ? `same garment identity: ${garmentIdentity}` : '', product.primary_color ? `primary color: ${product.primary_color}` : '', 'same clothing category, cut, fit, fabric finish, seams, panels, closure, neckline, waistband/pockets if visible across the full batch']),
    forbidden_inventions: uniqueList([p.forbidden_inventions || [], blockedBrandTerms.map(b => `${b} logo or wordmark`), 'random letters or numbers on garment', 'unapproved hangtag or label text']),
    quality_check: {
      ...(p.quality_check || {}),
      authorized_brand_only: true,
      no_third_party_logo: true,
      no_third_party_text: true,
      no_unapproved_label_or_hangtag: true,
      requires_reject_if_any_forbidden_brand_visible: true
    },
    idx: idx,
    ref_image_urls: (p.ref_image_ids || []).map(refToUrl).filter(Boolean)
  }
}));

