// Compute OSS keys and merge upstream metadata for every generated image in the current batch.
const items = $input.all();

return items.map((item, itemIndex) => {
  const incoming = item.json || {};
  const binary = item.binary;
  let meta;

  try {
    meta = $('拆分提示词清单').itemMatching(itemIndex).json;
  } catch (error) {
    const splitItems = $('拆分提示词清单').all();
    const paired = Array.isArray(item.pairedItem) ? item.pairedItem[0] : item.pairedItem;
    const fallbackIndex = Number.isInteger(paired && paired.item) ? paired.item : itemIndex;
    meta = (splitItems[fallbackIndex] && splitItems[fallbackIndex].json) || {};
  }

  const sku = meta.sku || 'unknown-sku';
  const runId = meta.run_id || 'unknown-run';
  const shotId = meta.shot_id || `shot_${itemIndex + 1}`;
  const idx = Number.isInteger(meta.idx) ? meta.idx : itemIndex + 1;
  const ossKey = `archive/${sku}/${runId}/${shotId}_${String(idx).padStart(2,'0')}.png`;
  const ossThumbKey = `archive/${sku}/${runId}/thumb_${shotId}_${String(idx).padStart(2,'0')}.jpg`;
  const arkRequestId = incoming.id || incoming.request_id || '';
  const arkUrl = (incoming.data && incoming.data[0] && incoming.data[0].url) || '';

  return {
    json: {
      ...meta,
      ark_request_id: arkRequestId,
      ark_image_url: arkUrl,
      oss_key: ossKey,
      oss_thumb_key: ossThumbKey,
      oss_bucket: 'yfn-content-factory',
      oss_endpoint: 'oss-cn-shanghai.aliyuncs.com',
      oss_url: `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/${ossKey}`,
      oss_thumb_url: `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/${ossThumbKey}`,
      generation_cost_cny: 0.30,
      image_bytes: binary && binary.data ? binary.data.fileSize || 0 : 0
    },
    binary: binary
  };
});

